/**
 * state session set 함수
 *
 * @private
 * @memberOf BxTree
 */
function _setSession(){

    let stateOptions = this.stateOptions;

    if (stateOptions.expire){
        let key = stateOptions.key;
        let session = STORAGE.sessionStorage.get(key);

        if (!session){
            STORAGE.localStorage.remove(key + '_state');
            STORAGE.sessionStorage.set(stateOptions.key, 'sessionOn');
        }
    }
}
/**
 * 현재 core data get 함수
 *
 * @returns {object} all data state
 * @private
 * @memberOf BxTree
 */
function _getAllNode(){

    let node = this.$container.jstree('get_json', '#')[0];

    let data  = _createCoreData.call(this, node);

    return data;

}
/**
 * state option set 함수
 *
 * @private
 * @memberOf BxTree
 */
function _setOptionState(){

    let state = _getState.call(this);

    _setItems(state, this.stateOptions.key + '_state');

}
/**
 * state option get 함수
 *
 * @returns {object} option state
 * @private
 * @memberOf BxTree
 */
function _getOptionState(){

    let stateOptions = this.stateOptions;
    let state = _getItems(stateOptions.key + '_state');

    if (stateOptions.fold){
        _initFoldState.call(this, state);
    }
    if (stateOptions.checkbox){
        _initCheckboxState.call(this, state);
    }
    if (stateOptions.selected){
        _initSelectedState.call(this, state);
    }
    if (stateOptions.disabled){
        _initDisabledState.call(this, state);
    }

    return state;
}
/**
 * 노드의 fold state 설정 함수
 *
 * @param {object} [state = {}] - 상태 저장 내역
 * @private
 * @memberOf BxTree
 */
function _initFoldState(state = {}){

    if (!_.isPlainObject(state)) CONSOLE.prop.throw(BxTree, 'state', 'type');

    let openNodes = state.open;
    if (openNodes.length){
        for (let i in openNodes){

            let node = this.$container.jstree('get_node', openNodes[i]);

            if (node) this.open(node);
        }
    }
}
/**
 * 노드의 checkbox state 설정 함수
 *
 * @param {object} [state = {}] - 상태 저장 내역
 * @private
 * @memberOf BxTree
 */
function _initCheckboxState(state = {}){

    if (!_.isPlainObject(state)) CONSOLE.prop.throw(BxTree, 'state', 'type');

    this.checkNodes(state.checked);
}
/**
 * 노드의 selected state 설정 함수
 *
 * @param {object} [state = {}] - 상태 저장 내역
 * @private
 * @memberOf BxTree
 */
function _initSelectedState(state = {}){

    if (!_.isPlainObject(state)) CONSOLE.prop.throw(BxTree, 'state', 'type');

    let node = this.$container.jstree('get_node', state.selected);

    this.selectedNode = node;
    this.$container.jstree('select_node', node, false, true);

}
/**
 * 노드의 disabled state 설정 함수
 *
 * @param {object} [state = {}] - 상태 저장 내역
 * @private
 * @memberOf BxTree
 */
function _initDisabledState(state = {}){

    if (!_.isPlainObject(state)) CONSOLE.prop.throw(BxTree, 'state', 'type');

    this.setDisableNodes(state.disabled);
}
/**
 * state get 함수
 *
 * @returns {object} state 값
 * @private
 * @memberOf BxTree
 */
function _getState(){

    let state = {
        'open': [],
        'checked': [],
        'selected': [],
        'disabled': []
    };

    let data = this.$container.jstree()._model.data;

    for (let i in data){
        if (data.hasOwnProperty(i)){
            if (i !== $.jstree.root){
                if (data[i].state.opened){
                    state.open.push(i);
                }
                if (data[i].state.checked){
                    state.checked.push(i);
                }
                if (data[i].state.selected){
                    state.selected.push(i);
                }
                if (data[i].state.disabled){
                    state.disabled.push(i);
                }
            }
        }
    }

    return state;

}
/**
 * localStorage에 items set 함수
 *
 * @param {object} data - jstree instance
 * @param {string} items key
 * @private
 * @memberOf BxTree
 */
function _setItems(data = {}, key = null){

    if (!_.isPlainObject(data)) CONSOLE.prop.throw(BxTree, 'data', 'type');

    if (!_.isString(key)) CONSOLE.prop.throw(BxTree, 'key', 'type');

    STORAGE.localStorage.set(key, JSON.stringify(data));
}

/**
 * localStorage에서 items get 함수
 *
 * @param {string} items key
 * @returns {object} data - store instance
 * @private
 * @memberOf BxTree
 */
function _getItems(key){

    if (!_.isString(key)) CONSOLE.prop.throw(BxTree, 'key', 'type');

    let storedItem = JSON.parse(STORAGE.localStorage.get(key));

    return storedItem;
}

/**
 * 노드의 초기 Open, Close 설정 함수
 *
 * @param {object} data - jsTree instance
 * @private
 * @memberOf BxTree
 */
function _initFirstOpen(data = {}){

    if (!_.isPlainObject(data)) CONSOLE.prop.throw(BxTree, 'data', 'type');

    let node = null;

    _.map(data.instance._model.data, (data, key) =>{
        if (this.isRootNode(data)){
            node = data;
        }
    });

    // 전체 node 를 open 시킨다.
    if (this.enableOpenAll){
        // 아이콘을 변경 시킨다.
        //this.setOpenIcon(node);
        this.$container.jstree('open_all', node);
    }
    else{
        this.$container.jstree('close_all', node);
    }

}

/**
 * 관계선 초기화 함수
 *
 * @private
 * @memberOf BxTree
 */
function _initSettingLine(isLine = null){

    let setLine;
    if (!_.isBoolean(isLine))  setLine = this.enableLine;
    else setLine = isLine;

    let type = this.lineType;
    let $node = this.$container.find(`.${TREE_CLASS.jstreeContainerUl}`);

    $node.removeClass(`${TREE_CLASS.lineType}`)
        .removeClass(`${TREE_CLASS.dotType}`)
        .removeClass(`${TREE_CLASS.noneType}`);

    if (!setLine){
        $node.addClass(`${TREE_CLASS.noneType}`);
    }
    else{
        if (type === 'dot'){
            $node.addClass(`${TREE_CLASS.dotType}`);
        }
        else{
            $node.addClass(`${TREE_CLASS.lineType}`);
        }
    }
}

/**
 * Node의 text의 태그를 삭제 한다.
 * @param {object} [node = {}] 아이템
 * @param {boolean} [isFlat=false] - flat 데이터 유무
 * @returns {object} - 생성된 인스턴스
 * @private
 * @memberOf BxTree
 */
function _parsing(node = {}, isFlat = false){

    if (!_.isPlainObject(node)) CONSOLE.prop.throw(BxTree, 'node', 'type');

    let obj = [];
    let nodeList = !isFlat ? [UTIL.toJSON(JSON.stringify(node))] : this.$container.jstree('get_json', node, {flat: isFlat});

    _.map(nodeList, data =>{

        obj.push({
            'id': data.id,
            'text': $(data.text).filter('span.text-node').html(),
            'icon': data.icon,
            'parent': data.parent,
            'children': data.children
        });
    });

    return !isFlat ? obj[0] : obj;
}

/**
 * CheckBox의 기능을 초기화 한다
 *
 * @param {boolean} [enableCheckRelated=false] - 상위 노드까지 체크의 유무
 * @param {boolean} [enableCheckLabel=false] - 라벨을 클릭 했을때 체크의 유무
 * @private
 * @memberOf BxTree
 */
function _initCheckBox(enableCheckRelated = false, enableCheckLabel = false){

    if (!_.isBoolean(enableCheckRelated) || !_.isBoolean(enableCheckLabel)){
        CONSOLE.prop.throw(BxTree, 'checkBoxOptions', 'type');
    }

    let opts = this[OPTS];

    opts.plugins.push('checkbox');

    opts.checkbox = {
        'three_state': enableCheckRelated,
        'whole_node': enableCheckLabel,
        'tie_selection': false // 체크, 선택 기능을 동등하게 볼지 여부
    };

    // whole_node 가 true일떄 Select 기능이 작동 안하도록 jstree는 되어 있어 core 코드와 동일하게 재구성
    if (opts.checkbox['whole_node']){

        this.$container.on('click', ".jstree-anchor", (e)=>{

            if (this.$container.jstree('is_disabled', e.currentTarget)) return;

            this.$container.jstree('deselect_all', true);
            this.$container.jstree('select_node', e.currentTarget, false, true, e);
            this.$container.jstree(true)['_data'].core['last_clicked'] = this.$container.jstree('get_node', (e.currentTarget));
        });
    }
}

/**
 * Drag and Drop의 기능을 초기화 한다
 *
 * @param {boolean} [insertPosition='before'] - 하위노드가 있는 노드로의 이동 시, 상단 또는 하단에 위치 지정
 * @private
 * @memberOf BxTree
 */
function _initDnd(insertPosition = 'before'){

    if (!_.isString(insertPosition)){
        CONSOLE.prop.throw(BxTree, 'insertPosition', 'type');
    }

    // 마우스 우측 현재노드(vakata-dnd)위치 수정
    $.vakata.dnd.settings = {
        "scroll_speed" : 10,
        "scroll_proximity" : 20,
        "helper_left" : 5,
        "helper_top" : -5, //10에서 -5로 수정
        "threshold" : 20,
        "threshold_touch" : 20
    };

    let opts = this[OPTS];

    opts.plugins.push('dnd');

    if (insertPosition === 'after') insertPosition = DND_OPTIONS.after;
    else insertPosition = DND_OPTIONS.before;

    opts.dnd = {
        'copy': false,
        'open_timeout': DND_OPTIONS.openTime,
        'inside_pos': insertPosition
    };
}

/**
 * Custom icon에 이벤트를 생성한다.
 *
 * @private
 * @memberOf BxTree
 */
function _setCustomIconHandler(){

    this.$container.off('click', '.jstree-ocl'); // jsTree 안에 있는 이벤트를 제거

    this.$container.on('click', '.jstree-themeicon-custom', (e) =>{

        this.toggle(this.$container.jstree('get_node', (e.currentTarget)));

        e.preventDefault();
        e.stopPropagation();
    });
}

/**
 * String or String[] 인지 유효성 검사를 한다
 * @param {string| string[] } [ids = null] 노드의 ID
 * @private
 * @memberOf BxTree
 */

function _validationOfString(ids = null){

    if (!(_.isArray(ids) || _.isString(ids))){
        CONSOLE.prop.throw(BxTree, 'ids', 'type');
        return this;
    }

    _.map(ids, id =>{

        if (!_.isString(id)){
            CONSOLE.prop.throw(BxTree, 'ids', 'type');
            return this;
        }
    });

    return this;
}

/**
 * 선택된 노드의 자식들을 반환한다
 *
 * @param {string} [id = null] 노드의 ID
 * @param {boolean} [isSelfNode = false] 선택된 노드가 함께 반환 여부
 * @returns {array} - 자식 노드들
 * @private
 * @memberOf BxTree
 */
function _getChildrensNode(id = null, isSelfNode = false){

    let nodeList = isSelfNode ? [id] : [];

    if (this.$container.jstree('get_node', id)){
        return nodeList.concat(this.$container.jstree()._model.data[id]['children_d']);
    }
    else{
        return nodeList;
    }
}
/**
 * 선택된 노드의 부모를 반환한다
 *
 * @param {string} [id = null] 노드의 ID
 * @param {boolean} [isSelfNode = false] 선택된 노드가 함께 반환 여부
 * @returns {array} - 부모 노드들
 * @private
 * @memberOf BxTree
 */
function _getParentsNode(id = null, isSelfNode = false){

    let nodeList = isSelfNode ? [id] : [];

    if (this.$container.jstree('get_node', id)){
        return nodeList.concat(this.$container.jstree()._model.data[id]['parents']);
    }
    else{
        return nodeList;
    }
}
/**
 * 업데이트 된 core.data 를 생성해준다.
 *
 * @param {object} [data = {}] jstree의 최신 트리정보
 * @returns {object} - 변화된 data
 * @private
 * @memberOf BxTree
 */
function _createCoreData(data = {}){

    _.cloneDeepWith(data, (nodeData = {}) =>{

        if (_.isPlainObject(nodeData)){

            delete nodeData['a_attr'];
            delete nodeData['data'];
            delete nodeData['li_attr'];
            delete nodeData['state'];
            nodeData['icon'] = $(nodeData['text']).filter('i').attr('class');
            nodeData['text'] = $(nodeData['text']).filter('span.text-node').html();
        }
    });

    return data;
}
module.exports = BxTree;